1	//! Zero-copy no_std SPSC ring buffer over a caller-provided
2	//! memory region, per [notes/ring-buffer-design.md]:
3	//!
4	//! - One `#[repr(C, align(64))]` [`Header`] spanning three cache
5	//!   lines (immutable geometry, producer index, consumer index),
6	//!   followed by M slots of N bytes.
7	//! - Indices are free-running `AtomicU32`s, masked only at slot
8	//!   access; full is `p - c == M`, no sacrificial slot.
9	//! - Messages move in place: the producer writes through a
10	//!   [`Reserved`] `&mut T`, the consumer reads through a
11	//!   [`Peeked`] `&T` — zerocopy traits bound `T`, no
12	//!   serialization step.
13	//!
14	//! [notes/ring-buffer-design.md]: https://github.com/winksaville/zc-ring-x1/blob/main/notes/ring-buffer-design.md
15	
16	#![cfg_attr(not(test), no_std)]
17	
18	use core::marker::PhantomData;
19	use core::mem::size_of;
20	use core::ops::{Deref, DerefMut};
21	use core::sync::atomic::{AtomicU32, Ordering};
22	use zerocopy::{FromBytes, Immutable, IntoBytes, KnownLayout};
23	
24	/// Cache-line size the layout is built around.
25	///
26	/// - Slot size must be a multiple of this; slots and the region
27	///   itself must be aligned to it.
28	pub const CACHE_LINE: usize = 64;
29	
30	/// Layout marker written by [`Ring::init`]; rejects foreign
31	/// regions on attach.
32	const MAGIC: u32 = 0x5A43_5231; // "ZCR1"
33	
34	/// Bumped on any change to the region layout.
35	const LAYOUT_VERSION: u32 = 1;
36	
37	/// Control block at offset 0 of the region — one struct spanning
38	/// three cache lines so each concurrently-written index owns its
39	/// own line.
40	///
41	/// - line 0: geometry, immutable after [`Ring::init`].
42	/// - line 1: `producer_idx`, written only by the producer.
43	/// - line 2: `consumer_idx`, written only by the consumer.
44	#[repr(C, align(64))]
45	pub struct Header {
46	    /// Layout marker ([`MAGIC`]).
47	    magic: u32,
48	    /// Layout version ([`LAYOUT_VERSION`]).
49	    layout_version: u32,
50	    /// Slot size N in bytes — a [`CACHE_LINE`] multiple.
51	    slot_size: u32,
52	    /// Slot count M — a power of two `<= 2^31`.
53	    capacity: u32,
54	    _pad0: [u8; 48],
55	    /// Free-running count of messages committed.
56	    producer_idx: AtomicU32,
57	    _pad1: [u8; 60],
58	    /// Free-running count of messages released.
59	    consumer_idx: AtomicU32,
60	    _pad2: [u8; 60],
61	}
62	
63	const _: () = assert!(size_of::<Header>() == 3 * CACHE_LINE);
64	
65	impl Header {
66	    /// Slot-position mask (`capacity - 1`).
67	    fn mask(&self) -> u32 {
68	        self.capacity - 1
69	    }
70	}
71	
72	/// Errors from [`Ring::init`] / [`Ring::attach`] region
73	/// validation.
74	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
75	pub enum Error {
76	    /// Region is not [`CACHE_LINE`]-aligned.
77	    Misaligned,
78	    /// Region is smaller than header + slots.
79	    TooSmall,
80	    /// Slot size is zero or not a [`CACHE_LINE`] multiple.
81	    BadSlotSize,
82	    /// Capacity is zero, not a power of two, or `> 2^31`.
83	    BadCapacity,
84	    /// Attach: magic mismatch — not a ring region.
85	    BadMagic,
86	    /// Attach: layout version mismatch.
87	    BadLayoutVersion,
88	}
89	
90	/// `reserve` failed: every slot holds an uncommitted-or-unread
91	/// message.
92	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
93	pub struct Full;
94	
95	/// `peek` failed: no unread messages.
96	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
97	pub struct Empty;
98	
99	/// A validated view over a ring region; split into the two
100	/// endpoint handles with [`Ring::split`].
101	pub struct Ring<'a> {
102	    /// The region's control block.
103	    header: &'a Header,
104	    /// Base of the slot array (offset `size_of::<Header>()`).
105	    slots: *mut u8,
106	    _region: PhantomData<&'a [u8]>,
107	}
108	
109	impl<'a> Ring<'a> {
110	    /// Initialize a fresh region and return the ring over it.
111	    ///
112	    /// - `slot_size` — N bytes per slot, a [`CACHE_LINE`]
113	    ///   multiple.
114	    /// - `capacity` — M slots, a power of two `<= 2^31`.
115	    /// - The region must be [`CACHE_LINE`]-aligned and at least
116	    ///   `size_of::<Header>() + M * N` bytes.
117	    pub fn init(region: &'a mut [u8], slot_size: u32, capacity: u32) -> Result<Self, Error> {
118	        validate_geometry(slot_size, capacity)?;
119	        if !(region.as_ptr() as usize).is_multiple_of(CACHE_LINE) {
120	            return Err(Error::Misaligned);
121	        }
122	        if region.len() < region_size(slot_size, capacity) {
123	            return Err(Error::TooSmall);
124	        }
125	        // SAFETY: region is exclusively borrowed for 'a, long
126	        // enough (checked above), CACHE_LINE-aligned (checked
127	        // above, and CACHE_LINE == align_of::<Header>()), and
128	        // any byte pattern is a valid Header.
129	        let header = unsafe { &mut *(region.as_mut_ptr() as *mut Header) };
130	        header.magic = MAGIC;
131	        header.layout_version = LAYOUT_VERSION;
132	        header.slot_size = slot_size;
133	        header.capacity = capacity;
134	        header.producer_idx = AtomicU32::new(0);
135	        header.consumer_idx = AtomicU32::new(0);
136	        // SAFETY: in bounds — region.len() >= header + slots.
137	        let slots = unsafe { region.as_mut_ptr().add(size_of::<Header>()) };
138	        Ok(Ring {
139	            header,
140	            slots,
141	            _region: PhantomData,
142	        })
143	    }
144	
145	    /// Attach to a region another process (or an earlier call)
146	    /// already initialized, validating its header.
147	    ///
148	    /// # Safety
149	    ///
150	    /// - `region` points to `len` bytes of memory that outlive
151	    ///   `'a`, genuinely shared and writable (e.g. a
152	    ///   `MAP_SHARED` mapping).
153	    /// - No other producer attaches if this side will produce;
154	    ///   likewise for the consumer side (SPSC contract).
155	    pub unsafe fn attach(region: *mut u8, len: usize) -> Result<Self, Error> {
156	        if !(region as usize).is_multiple_of(CACHE_LINE) {
157	            return Err(Error::Misaligned);
158	        }
159	        if len < size_of::<Header>() {
160	            return Err(Error::TooSmall);
161	        }
162	        // SAFETY: aligned + long enough (checked above); caller
163	        // guarantees the memory is live and shared.
164	        let header = unsafe { &*(region as *const Header) };
165	        if header.magic != MAGIC {
166	            return Err(Error::BadMagic);
167	        }
168	        if header.layout_version != LAYOUT_VERSION {
169	            return Err(Error::BadLayoutVersion);
170	        }
171	        validate_geometry(header.slot_size, header.capacity)?;
172	        if len < region_size(header.slot_size, header.capacity) {
173	            return Err(Error::TooSmall);
174	        }
175	        // SAFETY: in bounds — len >= header + slots.
176	        let slots = unsafe { region.add(size_of::<Header>()) };
177	        Ok(Ring {
178	            header,
179	            slots,
180	            _region: PhantomData,
181	        })
182	    }
183	
184	    /// Split into the producer and consumer endpoint handles.
185	    ///
186	    /// - Consuming `self` makes each handle exist at most once
187	    ///   per ring per process; cross-process, one producing and
188	    ///   one consuming process is the SPSC contract.
189	    pub fn split(self) -> (Producer<'a>, Consumer<'a>) {
190	        (
191	            Producer {
192	                header: self.header,
193	                slots: self.slots,
194	                _region: PhantomData,
195	            },
196	            Consumer {
197	                header: self.header,
198	                slots: self.slots,
199	                _region: PhantomData,
200	            },
201	        )
202	    }
203	}
204	
205	/// Bytes needed for a region with the given geometry.
206	fn region_size(slot_size: u32, capacity: u32) -> usize {
207	    size_of::<Header>() + slot_size as usize * capacity as usize
208	}
209	
210	/// Shared geometry checks for [`Ring::init`] / [`Ring::attach`].
211	fn validate_geometry(slot_size: u32, capacity: u32) -> Result<(), Error> {
212	    if slot_size == 0 || !(slot_size as usize).is_multiple_of(CACHE_LINE) {
213	        return Err(Error::BadSlotSize);
214	    }
215	    if capacity == 0 || !capacity.is_power_of_two() || capacity > 1 << 31 {
216	        return Err(Error::BadCapacity);
217	    }
218	    Ok(())
219	}
220	
221	/// Check `T` fits a slot; called once per reserve/peek.
222	///
223	/// - Panics on a type-geometry mismatch — that is a programming
224	///   error, not a runtime condition.
225	fn check_type<T>(header: &Header) {
226	    assert!(
227	        size_of::<T>() <= header.slot_size as usize,
228	        "T larger than slot"
229	    );
230	    assert!(
231	        core::mem::align_of::<T>() <= CACHE_LINE,
232	        "T alignment exceeds slot alignment"
233	    );
234	}
235	
236	/// Pointer to the slot for free-running index `idx`.
237	///
238	/// - Returned range is `header.slot_size` bytes, cache-line
239	///   aligned (base is, and slot_size is a line multiple).
240	fn slot_ptr(header: &Header, slots: *mut u8, idx: u32) -> *mut u8 {
241	    let pos = (idx & header.mask()) as usize;
242	    // SAFETY: pos < capacity, so the offset is inside the slot
243	    // array validated at init/attach.
244	    unsafe { slots.add(pos * header.slot_size as usize) }
245	}
246	
247	/// The producing endpoint: `reserve` a slot, write in place,
248	/// `commit`.
249	pub struct Producer<'a> {
250	    /// The ring's control block.
251	    header: &'a Header,
252	    /// Base of the slot array.
253	    slots: *mut u8,
254	    _region: PhantomData<&'a [u8]>,
255	}
256	
257	// SAFETY: the handle owns the producer role; the shared state it
258	// touches (indices) is atomic, and slot writes are handed off
259	// with Release/Acquire ordering.
260	unsafe impl Send for Producer<'_> {}
261	
262	impl<'a> Producer<'a> {
263	    /// Reserve the next free slot as a `&mut T`, or [`Full`].
264	    ///
265	    /// - Dropping the guard without [`Reserved::commit`]
266	    ///   abandons the reservation (nothing published).
267	    pub fn reserve<T>(&mut self) -> Result<Reserved<'_, T>, Full>
268	    where
269	        T: FromBytes + IntoBytes + KnownLayout,
270	    {
271	        check_type::<T>(self.header);
272	        let p = self.header.producer_idx.load(Ordering::Relaxed);
273	        let c = self.header.consumer_idx.load(Ordering::Acquire);
274	        if p.wrapping_sub(c) == self.header.capacity {
275	            return Err(Full);
276	        }
277	        let bytes = slot_ptr(self.header, self.slots, p);
278	        // SAFETY: index protocol gives the producer exclusive
279	        // access to this slot until commit; range validated at
280	        // init/attach.
281	        let bytes =
282	            unsafe { core::slice::from_raw_parts_mut(bytes, self.header.slot_size as usize) };
283	        #[allow(clippy::unwrap_used)]
284	        // OK: check_type guarantees size, slot base guarantees
285	        // alignment, so the prefix cast cannot fail.
286	        let (msg, _) = T::mut_from_prefix(bytes).unwrap();
287	        Ok(Reserved {
288	            header: self.header,
289	            msg,
290	            next_idx: p.wrapping_add(1),
291	        })
292	    }
293	}
294	
295	/// A reserved slot: `DerefMut` to write the message, then
296	/// [`commit`](Reserved::commit).
297	pub struct Reserved<'p, T> {
298	    /// The ring's control block (for the commit store).
299	    header: &'p Header,
300	    /// The slot, viewed as the message type.
301	    msg: &'p mut T,
302	    /// Value `producer_idx` takes on commit.
303	    next_idx: u32,
304	}
305	
306	impl<T> Deref for Reserved<'_, T> {
307	    type Target = T;
308	    /// Read access to the in-slot message.
309	    fn deref(&self) -> &T {
310	        self.msg
311	    }
312	}
313	
314	impl<T> DerefMut for Reserved<'_, T> {
315	    /// Write access to the in-slot message.
316	    fn deref_mut(&mut self) -> &mut T {
317	        self.msg
318	    }
319	}
320	
321	impl<T> Reserved<'_, T> {
322	    /// Publish the slot to the consumer
323	    /// (`producer_idx + 1`, `Release`).
324	    pub fn commit(self) {
325	        self.header
326	            .producer_idx
327	            .store(self.next_idx, Ordering::Release);
328	    }
329	}
