331	/// The consuming endpoint: `peek` the oldest unread slot, read
332	/// in place, `release`.
333	pub struct Consumer<'a> {
334	    /// The ring's control block.
335	    header: &'a Header,
336	    /// Base of the slot array.
337	    slots: *mut u8,
338	    _region: PhantomData<&'a [u8]>,
339	}
