345	impl<'a> Consumer<'a> {
346	    /// View the oldest unread slot as a `&T`, or [`Empty`].
347	    ///
348	    /// - Dropping the guard without [`Peeked::release`] leaves
349	    ///   the slot unread — the next peek returns it again.
350	    pub fn peek<T>(&mut self) -> Result<Peeked<'_, T>, Empty>
351	    where
352	        T: FromBytes + KnownLayout + Immutable,
353	    {
354	        check_type::<T>(self.header);
355	        let c = self.header.consumer_idx.load(Ordering::Relaxed);
356	        let p = self.header.producer_idx.load(Ordering::Acquire);
357	        if p == c {
358	            return Err(Empty);
359	        }
360	        let bytes = slot_ptr(self.header, self.slots, c);
361	        // SAFETY: index protocol gives the consumer exclusive
362	        // access to this slot until release; range validated at
363	        // init/attach.
364	        let bytes = unsafe {
365	            core::slice::from_raw_parts(bytes as *const u8, self.header.slot_size as usize)
