367	        #[allow(clippy::unwrap_used)]
368	        // OK: check_type guarantees size, slot base guarantees
369	        // alignment, so the prefix cast cannot fail.
370	        let (msg, _) = T::ref_from_prefix(bytes).unwrap();
371	        Ok(Peeked {
372	            header: self.header,
373	            msg,
374	            next_idx: c.wrapping_add(1),
375	        })
376	    }
377	}
