379	/// A peeked slot: `Deref` to read the message, then
380	/// [`release`](Peeked::release).
381	pub struct Peeked<'c, T> {
382	    /// The ring's control block (for the release store).
383	    header: &'c Header,
384	    /// The slot, viewed as the message type.
385	    msg: &'c T,
